#define cl(x) memset(x,0,sizeof x)
#define cli(x) memset(x,0x3f,sizeof x)
#define lowbit(x) (x&(-x))
#define wh while
#define gc() getchar()
#define pc(x) putchar(x)
#define NP namespace
#define ls (k<<1)
#define rs (k<<1|1)
using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int f[MAXN],n,m,ans=0;
int find(int x)
{
    return f[x]==x?x:f[x]=find(f[x]);
}
void merge(int x,int y)
{
    int fx=find(x);
    int fy=find(y);
    if(fx!=fy)
    {
        f[fx]=fy;
    }
}
void init()
{
    FOR(i,1,n<<1)
    {
        f[i]=i;
    }
}
signed main(void)
{
    n=read(),m=read();
    init();
    FOR(i,1,m)
    {
        char c;
        int x,y;
        cin>>c,x=read(),y=read();
        if(c=='F')
        {
            merge(x,y);
        }
        else
        {
            merge(y+n,x);
            merge(x+n,y);
        }
    }
    FOR(i,1,n)
    {
        if(f[i]==i)++ans;
    }
    writeln(ans);
    return false;
}
